CREATE TABLE "DCTerminalPolarityKind" ( "name" VARCHAR(100) UNIQUE );
-- Negative terminal.
INSERT INTO "DCTerminalPolarityKind" ( "name" ) VALUES ( 'negative' );
-- Positive terminal.
INSERT INTO "DCTerminalPolarityKind" ( "name" ) VALUES ( 'positive' );

