CREATE TABLE "InputSignalKind" ( "name" VARCHAR(100) UNIQUE );
-- Input signal is amplitude of remote branch current.
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'branchCurrent' );
-- Input signal is bus voltage fr<font color="#0f0f0f">equency. This could
-- be a terminal frequency or remote frequency.</font>
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'busFrequency' );
-- Input signal is deviation of bus voltage frequ<font color="#0f0f0f">ency.
-- This could be a terminal frequency deviation or remote frequency deviation.</font>
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'busFrequencyDeviation' );
-- Input signal <font color="#0f0f0f">is bus voltage. This could be a terminal
-- voltage or remote voltage.</font>
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'busVoltage' );
-- Input signal is derivative of bus voltag<font color="#0f0f0f">e. This could
-- be a terminal voltage derivative or remote voltage derivative.</font>
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'busVoltageDerivative' );
-- Input signal is generator field current.
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'fieldCurrent' );
-- Input signal is generator accelerating power.
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'generatorAcceleratingPower' );
-- Input signal is generator electrical power on rated <i>S</i>.
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'generatorElectricalPower' );
-- Input signal is generator mechanical power.
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'generatorMechanicalPower' );
-- Input signal is rotor or shaft angular frequency (speed) deviation.
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'rotorAngularFrequencyDeviation' );
-- Input signal is rotor or shaft speed (angular frequency).
INSERT INTO "InputSignalKind" ( "name" ) VALUES ( 'rotorSpeed' );

-- Limit kinds.
CREATE TABLE "LimitKind" ( "name" VARCHAR(100) UNIQUE );
-- Voltage alarm.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'alarmVoltage' );
-- Referring to the rating of the equipments, a voltage too high can lead
-- to accelerated ageing or the destruction of the equipment.
-- This limit type may or may not have duration.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'highVoltage' );
-- A too low voltage can disturb the normal operation of some protections
-- and transformer equipped with on-load tap changers, electronic power devices
-- or can affect the behaviour of the auxiliaries of generation units.
-- This limit type may or may not have duration.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'lowVoltage' );
-- Operational voltage limit.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'operationalVoltageLimit' );
-- The Permanent Admissible Transmission Loading (PATL) is the loading in
-- amperes, MVA or MW that can be accepted by a network branch for an unlimited
-- duration without any risk for the material.
-- The OperationnalLimitType.isInfiniteDuration is set to true. There shall
-- be only one OperationalLimitType of kind PATL per OperationalLimitSet if
-- the PATL is ApparentPowerLimit, ActivePowerLimit, or CurrentLimit for a
-- given Terminal or Equipment.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'patl' );
-- Permanent Admissible Transmission Loading Threshold (PATLT) is a value
-- in engineering units defined for PATL and calculated using a percentage
-- less than 100 % of the PATL type intended to alert operators of an arising
-- condition. The percentage should be given in the name of the OperationalLimitSet.
-- The aceptableDuration is another way to express the severity of the limit.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'patlt' );
-- Stability.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'stability' );
-- Temporarily Admissible Transmission Loading (TATL) which is the loading
-- in amperes, MVA or MW that can be accepted by a branch for a certain limited
-- duration.
-- The TATL can be defined in different ways:
-- <ul>
-- <li>as a fixed percentage of the PATL for a given time (for example, 115%
-- of the PATL that can be accepted during 15 minutes),</li>
-- </ul>
-- <ul>
-- <li>pairs of TATL type and Duration calculated for each line taking into
-- account its particular configuration and conditions of functioning (for
-- example, it can define a TATL acceptable during 20 minutes and another
-- one acceptable during 10 minutes).</li>
-- </ul>
-- Such a definition of TATL can depend on the initial operating conditions
-- of the network element (sag situation of a line).
-- The duration attribute can be used to define several TATL limit types.
-- Hence multiple TATL limit values may exist having different durations.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'tatl' );
-- Tripping Current (TC) is the ultimate intensity without any delay. It is
-- defined as the threshold the line will trip without any possible remedial
-- actions.
-- The tripping of the network element is ordered by protections against short
-- circuits or by overload protections, but in any case, the activation delay
-- of these protections is not compatible with the reaction delay of an operator
-- (less than one minute).
-- The duration is always zero if the OperationalLimitType.acceptableDuration
-- is exchanged. Only one limit value exists for the TC type.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'tc' );
-- Tripping Current Threshold (TCT) is a value in engineering units defined
-- for TC and calculated using a percentage less than 100 % of the TC type
-- intended to alert operators of an arising condition. The percentage should
-- be given in the name of the OperationalLimitSet. The aceptableDuration
-- is another way to express the severity of the limit.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'tct' );
-- Voltage warning.
INSERT INTO "LimitKind" ( "name" ) VALUES ( 'warningVoltage' );

-- A linear shunt compensator has banks or sections with equal admittance
-- values.
CREATE TABLE "LinearShuntCompensator"
(
    "mRID" VARCHAR(100) PRIMARY KEY,
    -- Positive sequence shunt (charging) susceptance per section.
    "bPerSection" DOUBLE PRECISION NOT NULL,
    -- Positive sequence shunt (charging) conductance per section.
    "gPerSection" DOUBLE PRECISION NOT NULL
);

-- Models the characteristic response of the load demand due to changes in
-- system conditions such as voltage and frequency. It is not related to demand
-- response.
-- If LoadResponseCharacteristic.exponentModel is True, the exponential voltage
-- or frequency dependent models are specified and used as to calculate active
-- and reactive power components of the load model.
-- The equations to calculate active and reactive power components of the
-- load model are internal to the power flow calculation, hence they use different
-- quantities depending on the use case of the data exchange.
-- The equations for exponential voltage dependent load model injected power
-- are:
-- pInjection= Pnominal* (Voltage/cim:BaseVoltage.nominalVoltage) ** cim:LoadResponseCharacteristic.pVoltageExponent
-- qInjection= Qnominal* (Voltage/cim:BaseVoltage.nominalVoltage) ** cim:LoadResponseCharacteristic.qVoltageExponent
-- pInjection = Pnominal* (Frequency/(Nominal frequency))**cim:LoadResponseCharacteristic.pFrequencyExponent
-- qInjection = Qnominal* (Frequency/(Nominal frequency))**cim:LoadResponseCharacteristic.qFrequencyExponent
-- Note that both voltage and frequency exponents could be used together so
-- the full equation would be:
-- pInjection = Pnominal* (Voltage/(cim:BaseVoltage.nominalVoltage))**cim:LoadResponseCharacteristic.pVoltageExponent
-- * (Frequency/(base frequency))**cim:LoadResponseCharacteristic.pFrequencyExponent
-- qInjection = Qnominal* (Voltage/(cim:BaseVoltage.nominalVoltage))**cim:LoadResponseCharacteristic.qVoltageExponent
-- * (Frequency/(base frequency))**cim:LoadResponseCharacteristic.qFrequencyExponent
-- The voltage and frequency expressed in the equation are values obtained
-- from solved power flow. Base voltage and base frequency are those derived
-- from the connectivity of the static network model.
-- Where:
-- 1) * means "multiply" and ** is "raised to the power of";
-- 2) Pnominal and Qnominal represent the active power and reactive power
-- at nominal voltage as any load described by the voltage exponential model
-- shall be given at nominal voltage. This means that EnergyConsumer.p and
-- EnergyConsumer.q are at nominal voltage.
-- 3) After power flow is solved:
-- -pInjection and qInjection correspond to SvPowerflow.p and SvPowerflow.q
-- respectively.
-- - Voltage corresponds to SvVoltage.v at the TopologicalNode where the load
-- is connected.
CREATE TABLE "LoadResponseCharacteristic"
(
    "mRID" VARCHAR(100) PRIMARY KEY,
    -- Indicates the exponential voltage dependency model is to be used. If false,
    -- the coefficient model is to be used.
    -- The exponential voltage dependency model consist of the attributes:
    -- - pVoltageExponent
    -- - qVoltageExponent
    -- - pFrequencyExponent
    -- - qFrequencyExponent.
    -- The coefficient model consist of the attributes:
    -- - pConstantImpedance
    -- - pConstantCurrent
    -- - pConstantPower
    -- - qConstantImpedance
    -- - qConstantCurrent
    -- - qConstantPower.
    -- The sum of pConstantImpedance, pConstantCurrent and pConstantPower shall
    -- equal 1.
    -- The sum of qConstantImpedance, qConstantCurrent and qConstantPower shall
    -- equal 1.
    "exponentModel" INTEGER NOT NULL DEFAULT 1 CHECK ("exponentModel" IN (0, 1)) NOT NULL,
    -- Portion of active power load modelled as constant current.
    "pConstantCurrent" DOUBLE PRECISION NOT NULL,
    -- Portion of active power load modelled as constant impedance.
    "pConstantImpedance" DOUBLE PRECISION NOT NULL,
    -- Portion of active power load modelled as constant power.
    "pConstantPower" DOUBLE PRECISION NOT NULL,
    -- Exponent of per unit frequency effecting active power.
    "pFrequencyExponent" DOUBLE PRECISION NOT NULL,
    -- Exponent of per unit voltage effecting real power.
    "pVoltageExponent" DOUBLE PRECISION NOT NULL,
    -- Portion of reactive power load modelled as constant current.
    "qConstantCurrent" DOUBLE PRECISION NOT NULL,
    -- Portion of reactive power load modelled as constant impedance.
    "qConstantImpedance" DOUBLE PRECISION NOT NULL,
    -- Portion of reactive power load modelled as constant power.
    "qConstantPower" DOUBLE PRECISION NOT NULL,
    -- Exponent of per unit frequency effecting reactive power.
    "qFrequencyExponent" DOUBLE PRECISION NOT NULL,
    -- Exponent of per unit voltage effecting reactive power.
    "qVoltageExponent" DOUBLE PRECISION NOT NULL
);

-- Use to define machine saturation with more than two points. xUnit is A
-- (RMS current) and y1Unit is none (per-unit voltage).
CREATE TABLE "MachineSaturationCurve"
(
    "mRID" VARCHAR(100) PRIMARY KEY,
    -- The synchronous machine this saturation characteristic applies to.
    -- FK column reference to table representing the "SynchronousMachineDetailed" class
    "SynchronousMachineDetailed" VARCHAR(100)
);

-- This class represents the zero sequence line mutual coupling.
CREATE TABLE "MutualCoupling"
(
    "mRID" VARCHAR(100) PRIMARY KEY,
    -- Zero sequence mutual coupling shunt (charging) susceptance, uniformly distributed,
    -- of the entire line section.
    "b0ch" DOUBLE PRECISION,
    -- Distance to the start of the coupled region from the first line's terminal
    -- having sequence number equal to 1.
    "distance11" DOUBLE PRECISION,
    -- Distance to the end of the coupled region from the first line's terminal
    -- with sequence number equal to 1.
    "distance12" DOUBLE PRECISION,
    -- Distance to the start of coupled region from the second line's terminal
    -- with sequence number equal to 1.
    "distance21" DOUBLE PRECISION,
    -- Distance to the end of coupled region from the second line's terminal with
    -- sequence number equal to 1.
    "distance22" DOUBLE PRECISION,
    -- Zero sequence mutual coupling shunt (charging) conductance, uniformly distributed,
    -- of the entire line section.
    "g0ch" DOUBLE PRECISION,
    -- The name is any free human readable and possibly non unique text naming
    -- the object.
    "name" VARCHAR(255) NOT NULL,
    -- Zero sequence branch-to-branch mutual impedance coupling, resistance.
    "r0" DOUBLE PRECISION,
    -- Zero sequence branch-to-branch mutual impedance coupling, reactance.
    "x0" DOUBLE PRECISION
);

